propData.styleConfig:
#domId {
  background: rgba(255, 255, 255, 1);
}

#domId .el-table {
  /*height: calc(100% - 44px) !important;*/
  background: rgba(255, 255, 255, 1);
  font-family: 思源黑体;
}

/*#domId table.el-table__header {*/
/*  border-top: 1px solid #dedede;*/
/*  border-left: 1px solid #dedede;*/
/*}*/

/*表格header的背景色*/
#domId .el-table__header tr {
  background: #F8F8F8;
  color: #3d3d3d;
}

#domId .el-table__header th {
  background: #F8F8F8;
  color: #3d3d3d;
  /*border-right: 1px solid #dedede;*/
  border-bottom: 1px solid #dedede;
  height: 45px;
  padding: 0;
  font-size: 14px;
  font-family: 思源黑体;
  font-style: normal;
  font-weight: bold;
}

#domId .el-table tbody tr {
  height: 40px;
  font-size: 14px;
  font-family: 思源黑体;
  font-style: normal;
  font-weight: normal;
}


#domId .el-table tbody tr {
  background: #fff;
  color: #3d3d3d;
}


/*#domId .el-table tbody tr>td:first-child {*/
/*  border-left: 1px solid #dedede;*/
/*}*/

#domId .el-table tbody tr>td {
  background: #fff;
  color: #3d3d3d;
  border-bottom: 1px solid #dedede;
  /*border-right: 1px solid #dedede;*/
}


#domId .el-table tbody tr:hover,
#domId .el-table tbody tr:hover>td {
  background: #f2f8ff;
  /*color: #000;*/
  font-weight: 500;
  cursor: pointer;
}


#domId .el-table tbody tr.current-row,
#domId .el-table tbody tr.current-row>td {
  background: #F1F4FF;
  color: #0076FF;
}


#domId tr.el-table__row td.el-table__cell:last-child button {
  color: #0076FF;
}

#domId tr.el-table__row td.el-table__cell:last-child button.el-button:last-child {
  color: #FF5B51;
}

#domId .el-checkbox__input.is-checked .el-checkbox__inner,
#domId .el-checkbox__input.is-indeterminate .el-checkbox__inner {
  background-color: #0076FF;
  border-color: #0076FF;
}

#domId .el-checkbox__input .el-checkbox__inner:hover {
  border-color: #0076FF;
}

#domId .el-button--text {
  color: #0076ff;
}

#domId .el-table tbody tr>.el-table-column--selection .el-checkbox__inner {
  border-width: 1px;
}

#domId .el-table tbody tr>.el-table-column--selection .is-checked .el-checkbox__inner {
  border-width: 2px;
}


#domId .cell .el-input__inner {
  border: none;
}

#domId tr.el-table__row td.el-table__cell .el-button--text {
  background: transparent;
  padding-left: 0;
  padding-right: 0;
  padding-top: 0;
  padding-bottom: 0;
}


/* 隐藏采集设备实例行的形参管理按钮 */
#domId .el-table .el-table__body .kf-row-dce-instance .el-table__cell .cell>button:nth-child(4) {
  display: none;
}

#domId .el-table .el-table__body .kf-row-mcm-instance .instance-name.el-table__cell .cell span:last-child {
  background-image: url("data:image/svg+xml;charset=utf-8;base64,");
  background-repeat: no-repeat;
  background-position: left center;
  background-size: auto;
  padding-left: 20px;
}


#domId .el-table .el-table__body .kf-row-dce-instance .instance-name.el-table__cell .cell span:last-child {
  background-image: url("data:image/svg+xml;charset=utf-8;base64,");
  background-repeat: no-repeat;
  background-position: left center;
  background-size: auto;
  padding-left: 20px;
}

/*分页*/
