    justify-content: start;
    background: rgba(255, 255, 255, 0);
    margin-top: 0;
} */


#domId .pagination-container {
  display: flex;
  justify-content: flex-end;
  align-items: center;
  padding: 10px 0 0 0;
}

#domId .el-pagination {
  background: rgba(255, 255, 255, 0);
}

#domId .el-pagination span {
  font-size: 13px;
  font-family: 思源黑体;
  font-style: normal;
  font-weight: normal;
}

#domId .el-pagination input,
#domId .el-pagination button {
  background: rgba(255, 255, 255, 0);
  color: rgba(48, 49, 51, 1);
  border: 1px solid rgba(235, 238, 245, 1);
  font-size: 13px;
  font-family: 思源黑体;
  font-style: normal;
  font-weight: normal;
}

#domId .el-pagination li {
  background: rgba(255, 255, 255, 0);
  color: rgba(48, 49, 51, 1);
  font-size: 13px;
  font-family: 思源黑体;
  font-style: normal;
  font-weight: normal;
}

#domId .el-pagination li.active {
  background: rgba(255, 255, 255, 1);
  color: rgba(47, 84, 235, 1);
}

#domId .el-table__body-wrapper::-webkit-scrollbar {
  width: 8px;
}

#domId .el-table__body-wrapper::-webkit-scrollbar-thumb {
  background: rgba(221, 221, 221, 1);
}

